SELECT AVG(turnout_percentage) AS average_turnout_percentage
FROM voter_turnout
WHERE election_id = 1;

SELECT precinct_id, COUNT(turnout_id) AS total_turnout_records
FROM voter_turnout
GROUP BY precinct_id;

SELECT SUM(ballots_cast) AS total_votes_cast
FROM ballots_cast
WHERE election_id = 1;

SELECT location_name, location_type, contact_email
FROM locations
ORDER BY location_name;

SELECT precinct_id, AVG(ballots_cast) AS average_ballots_cast
FROM ballots_cast
GROUP BY precinct_id;

SELECT SUM(turnout_percentage) AS total_turnout_percentage
FROM voter_turnout
WHERE turnout_percentage > 50;
